import { Vec3, type ScriptContext, type Vec3Tuple } from "@threenative/script-stdlib";

type PuckState = {
  active: boolean;
  velocity: Vec3Tuple;
};

type TargetState = {
  knocked: boolean;
  start: Vec3Tuple;
};

type GameState = {
  phase: string;
  score: number;
  shots: number;
  targets: number;
  scoreText: string;
  shotsText: string;
  status: string;
};

export function updateKnockdownGame(context: ScriptContext): void {
  const targetIds = ["target.01", "target.02", "target.03", "target.04", "target.05", "target.06"];
  const launcherStart: Vec3Tuple = [0, 0.22, 3.2];
  const puckReadyOffset: Vec3Tuple = [0, -0.02, -0.72];
  const puckReadyY = 0.2;
  const finite = (value: unknown, fallback: number): number => typeof value === "number" && Number.isFinite(value) ? value : fallback;
  const clamp = (value: number, min: number, max: number): number => Math.max(min, Math.min(max, value));
  const vec3 = (value: unknown, fallback: Vec3Tuple): Vec3Tuple => Array.isArray(value) && value.length === 3
    ? [finite(value[0], fallback[0]), finite(value[1], fallback[1]), finite(value[2], fallback[2])]
    : fallback;
  const readGameState = (): GameState => context.resources.get("GameState", {
    phase: "aiming",
    score: 0,
    shots: 0,
    targets: targetIds.length,
    scoreText: "Score 0/6",
    shotsText: "Shots 0",
    status: "Move with WASD or arrows. Space/Enter launches. R retries."
  });
  const patchGameState = (patch: Partial<GameState>): void => {
    context.resources.patch("GameState", patch);
  };
  const resetGame = (): void => {
  const launcher = context.entity("launcher");
  const puck = context.entity("puck");
  launcher?.transform().setPosition(launcherStart);
  launcher?.patch("Launcher", { cooldown: 0 });
  const puckReady = Vec3.add(launcherStart, puckReadyOffset);
  puckReady[1] = puckReadyY;
  puck?.transform().setPosition(puckReady);
  puck?.patch("Puck", { active: false, velocity: [0, 0, 0] });

  for (const id of targetIds) {
    const target = context.entity(id);
    if (target === undefined) continue;
    const targetState = target.get<TargetState>("KnockTarget", { knocked: false, start: target.transform().position });
    const start = vec3(targetState.start, target.transform().position);
    target.transform().setPosition(start);
    target.transform().setRotation([0, 0, 0, 1]);
    target.patch("KnockTarget", { knocked: false, start });
  }

  patchGameState(context, {
    phase: "aiming",
    score: 0,
    shots: 0,
    targets: targetIds.length,
    scoreText: `Score 0/${targetIds.length}`,
    shotsText: "Shots 0",
    status: "Aim with WASD/arrows, then press Space or Enter."
  });
  };
  const launcher = context.entity("launcher");
  const puck = context.entity("puck");
  if (launcher === undefined || puck === undefined) return;

  const delta = Math.max(0, context.time.fixedDelta);
  const state = gameState(context);

  if (context.input.getButtonDown("retry") || context.input.getButton("retry")) {
    resetGame();
    return;
  }

  const launcherTransform = launcher.transform();
  const launcherPosition = launcherTransform.position;
  const moveX = context.input.getAxis("MoveX");
  const moveZ = context.input.getAxis("MoveZ");
  const movedLauncher: Vec3Tuple = [
    clamp(launcherPosition[0] + moveX * delta * 3.2, -3.2, 3.2),
    launcherStart[1],
    clamp(launcherPosition[2] + moveZ * delta * 2.4, 1.25, 3.55)
  ];
  launcherTransform.setPosition(movedLauncher);

  const puckState = puck.get<PuckState>("Puck", { active: false, velocity: [0, 0, 0] });
  const puckTransform = puck.transform();
  let puckPosition = puckTransform.position;
  let puckVelocity = vec3(puckState.velocity, [0, 0, 0]);
  const isActive = puckState.active === true;

  if (!isActive) {
    const ready = Vec3.add(movedLauncher, puckReadyOffset);
    ready[1] = puckReadyY;
    puckTransform.setPosition(ready);
    puck.patch("Puck", { active: false, velocity: [0, 0, 0] });
    puckPosition = ready;
  }

  if (!isActive && (context.input.getButtonDown("launch") || context.input.getButton("launch"))) {
    const aimX = clamp(movedLauncher[0] * 0.55, -1.6, 1.6);
    puckVelocity = [aimX, 0, -7.6];
    puck.patch("Puck", { active: true, velocity: puckVelocity });
    patchGameState(context, {
      phase: "rolling",
      shots: state.shots + 1,
      shotsText: `Shots ${state.shots + 1}`,
      status: "Puck launched. Knock every target out of place."
    });
  } else if (isActive) {
    puckVelocity = [puckVelocity[0] * 0.992, 0, puckVelocity[2] * 0.992];
    puckPosition = Vec3.add(puckPosition, Vec3.scale(puckVelocity, delta));
    puckTransform.setPosition(puckPosition);
    puck.patch("Puck", { active: true, velocity: puckVelocity });
  }

  let score = finite(state.score, 0);
  for (const id of targetIds) {
    const target = context.entity(id);
    if (target === undefined) continue;
    const targetState = target.get<TargetState>("KnockTarget", { knocked: false, start: target.transform().position });
    if (targetState.knocked) continue;

    const targetPosition = target.transform().position;
    const dx = puckPosition[0] - targetPosition[0];
    const dz = puckPosition[2] - targetPosition[2];
    const hitDistance = Math.sqrt(dx * dx + dz * dz);
    if (isActive && hitDistance < 0.55) {
      const pushX = dx >= 0 ? -0.78 : 0.78;
      const newPosition: Vec3Tuple = [targetPosition[0] + pushX, 0.21, targetPosition[2] - 0.34];
      target.transform().setPosition(newPosition);
      target.transform().setRotation([0.32, 0, pushX > 0 ? -0.58 : 0.58, 0.75]);
      target.patch("KnockTarget", { knocked: true, start: vec3(targetState.start, targetPosition) });
      score += 1;
      puckVelocity = [puckVelocity[0] * 0.72 + pushX * -0.8, 0, puckVelocity[2] * 0.86];
      puck.patch("Puck", { active: true, velocity: puckVelocity });
    }
  }

  const totalTargets = targetIds.length;
  const outOfBounds = puckPosition[2] < -5.4 || Math.abs(puckPosition[0]) > 4.2 || Math.abs(puckVelocity[2]) < 0.45;
  if (isActive && outOfBounds) {
    const ready = Vec3.add(movedLauncher, puckReadyOffset);
    ready[1] = puckReadyY;
    puckTransform.setPosition(ready);
    puck.patch("Puck", { active: false, velocity: [0, 0, 0] });
    patchGameState(context, {
      phase: score >= totalTargets ? "won" : "aiming",
      score,
      scoreText: `Score ${score}/${totalTargets}`,
      status: score >= totalTargets ? "All targets down. Press R to play again." : "Aim again, launch with Space or Enter, or press R to retry."
    });
    return;
  }

  patchGameState(context, {
    phase: score >= totalTargets ? "won" : state.phase,
    score,
    scoreText: `Score ${score}/${totalTargets}`,
    status: score >= totalTargets ? "All targets down. Press R to play again." : state.status
  });
}

